DROP TABLE IF EXISTS `notification_messages`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `notification_messages` (
  `id` bigint NOT NULL AUTO_INCREMENT,
  `batch_no` varchar(32) NOT NULL,
  `msg_type` varchar(32) NOT NULL,
  `content` varchar(500) NOT NULL,
  `sender_id` bigint NOT NULL,
  `sender_name` varchar(64) NOT NULL,
  `receiver_id` bigint NOT NULL,
  `receiver_name` varchar(64) NOT NULL,
  `send_time` timestamp NOT NULL DEFAULT CURRENT_TIMESTAMP,
  `is_read` tinyint NOT NULL DEFAULT '0',
  `read_time` timestamp NULL DEFAULT NULL,
  `is_deleted` tinyint NOT NULL DEFAULT '0',
  `deleted_time` timestamp NULL DEFAULT NULL,
  `target_type` varchar(32) NOT NULL,
  `target_value` varchar(128) DEFAULT NULL,
  `created_at` timestamp NOT NULL DEFAULT CURRENT_TIMESTAMP,
  `updated_at` timestamp NOT NULL DEFAULT CURRENT_TIMESTAMP,
  PRIMARY KEY (`id`),
  KEY `idx_notification_receiver_deleted` (`receiver_id`,`is_deleted`,`send_time`),
  KEY `idx_notification_receiver_unread` (`receiver_id`,`is_deleted`,`is_read`),
  KEY `idx_notification_batch_no` (`batch_no`)
) ENGINE=InnoDB AUTO_INCREMENT=683 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci;
/*!40101 SET character_set_client = @saved_cs_client */;

