  `updated_at` timestamp NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP,
  PRIMARY KEY (`id`),
  UNIQUE KEY `uk_units_building_unit_no` (`building_id`,`unit_no`),
  KEY `idx_units_building_id` (`building_id`),
  KEY `idx_units_owner_resident_id` (`owner_resident_id`),
